import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { validateAudience } from "../portauth-engine/src/services/credentialVerifier.js";
import { evaluateConstraints } from "../portauth-engine/src/services/constraintEvaluator.js";
import { validateDelegationLink, verifyAttenuation } from "../portauth-engine/src/services/delegationVerifier.js";
import { buildMappingCacheFromRows } from "../portauth-engine/src/services/semanticResolver.js";
import {
  parseX5cChain,
  pemCertificatesToX5c,
  validateCertificateIdentity,
  verifyX509ChainFromHeader,
} from "../portauth-engine/src/services/x509Verifier.js";
import {
  evaluateStatefulConstraints,
  MemoryStatefulStore,
} from "../portauth-engine/src/services/statefulAuthorizer.js";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const vectorDir = path.join(__dirname, "vectors");

async function readText(relativePath) {
  return fs.readFile(path.join(__dirname, relativePath), "utf8");
}

async function loadVectors() {
  const files = (await fs.readdir(vectorDir)).filter((file) => file.endsWith(".json")).sort();
  const vectors = [];
  for (const file of files) {
    const parsed = JSON.parse(await fs.readFile(path.join(vectorDir, file), "utf8"));
    vectors.push(...parsed.map((vector) => ({ ...vector, file })));
  }
  return vectors;
}

function expectedOutcome(vector, actual) {
  if (actual.pass !== vector.expected.pass) {
    return { ok: false, message: `expected pass=${vector.expected.pass}, got pass=${actual.pass}` };
  }
  if (vector.expected.errorCode && actual.errorCode !== vector.expected.errorCode) {
    return { ok: false, message: `expected errorCode=${vector.expected.errorCode}, got ${actual.errorCode}` };
  }
  return { ok: true };
}

async function runVector(vector) {
  const { input } = vector;

  if (vector.type === "audience") {
    const result = validateAudience(input.aud, { evaluatorId: input.evaluatorId });
    return { pass: result.pass, errorCode: result.errorCode || null };
  }

  if (vector.type === "constraints") {
    const result = await evaluateConstraints(input.constraints, input.context);
    return { pass: result.pass, errorCode: result.error || null };
  }

  if (vector.type === "delegationLink") {
    const result = validateDelegationLink(input.parent, input.child);
    return { pass: result.valid, errorCode: result.valid ? null : "delegation_chain_broken" };
  }

  if (vector.type === "attenuation") {
    const result = verifyAttenuation(input.parent, input.child);
    return { pass: result.valid, errorCode: result.valid ? null : "delegation_widened" };
  }

  if (vector.type === "mappingProfile") {
    const mappings = buildMappingCacheFromRows(input.rows, new Date(input.now || "2026-06-10T00:00:00Z"));
    const mapping = mappings.get(input.semanticField);
    const errorCode = mapping?.errorCode || null;
    return { pass: !errorCode, errorCode };
  }

  if (vector.type === "x509Chain") {
    const chainPem = (await Promise.all(input.chainPemFiles.map(readText))).join("\n");
    const trustAnchorPem = await readText(input.trustAnchorPemFile);
    const x5c = pemCertificatesToX5c(chainPem);
    const chainResult = verifyX509ChainFromHeader({ x5c }, {
      trustAnchorsPem: trustAnchorPem,
      now: new Date(input.now),
    });
    if (!chainResult.pass) {
      return { pass: false, errorCode: chainResult.errorCode };
    }
    const [leaf] = parseX5cChain(x5c);
    const identityResult = validateCertificateIdentity(leaf, input.issuerId, {
      x509_san_uri: input.x509SanUri,
    });
    return { pass: identityResult.pass, errorCode: identityResult.errorCode || null };
  }

  if (vector.type === "statefulSequence") {
    const store = new MemoryStatefulStore();
    for (const request of input.requests) {
      const result = await evaluateStatefulConstraints(input.constraints, request.context, input.payload, {
        store,
        now: new Date(input.now),
      });
      if (result.pass !== request.expectedPass) {
        return {
          pass: false,
          errorCode: result.error || "conformance_mismatch",
        };
      }
    }
    return { pass: true, errorCode: null };
  }

  return { pass: false, errorCode: "unknown_vector_type" };
}

export async function runConformance({ silent = false } = {}) {
  const vectors = await loadVectors();
  const results = [];

  for (const vector of vectors) {
    const actual = await runVector(vector);
    const expected = expectedOutcome(vector, actual);
    const result = {
      id: vector.id,
      file: vector.file,
      requirement: vector.requirement,
      ok: expected.ok,
      actual,
      message: expected.message || "ok",
    };
    results.push(result);
    if (!silent) {
      const mark = result.ok ? "PASS" : "FAIL";
      console.log(`${mark} ${result.id} ${result.requirement}`);
      if (!result.ok) console.log(`  ${result.message}`);
    }
  }

  const failures = results.filter((result) => !result.ok);
  if (!silent) {
    console.log(`\n${results.length - failures.length}/${results.length} conformance vectors passed`);
  }

  return { pass: failures.length === 0, results, failures };
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const outcome = await runConformance();
  process.exit(outcome.pass ? 0 : 1);
}
